const items=$input.all();
const today=new Date();

// Clasificar estados
const COMPLETADOS=['Conseguida','Cerrada','Rechazada','Solicitud perdida','Retirada'];
const PENDIENTE=['Enviada','Sin respuesta','Requiere mi acción'];
const EN_PROGRESO=['CV Visto','Primer contacto','Primera llamada','Próximo a reunión','En contacto','Reunión agendada','Esperando decisión'];

const grupos={};
const necesitanAccion=[];
const sinRespuesta30=[];
const sincerrar=[];

let activas=0, completadas=0, sinEstado=0;

for(const item of items){
  const p=item.json.properties||{};
  const estadoRaw=p['Estado']?.status?.name||'';
  const nombre=(p['Nombre']?.title||[]).map(t=>t.plain_text).join('')||'Sin nombre';
  const empresa=(p['Empresa🔸']?.rich_text||[]).map(t=>t.plain_text).join('')||'';
  const fechaPost=p['Fecha de postulación']?.date?.start;
  const diasTranscurridos=fechaPost?Math.floor((today-new Date(fechaPost))/86400000):null;

  // Normalizar estado (quitar emojis al inicio)
  const estado=estadoRaw.replace(/^[^a-zA-ZáéíóúÁÉÍÓÚ]+/,'').trim();

  if(!estadoRaw){sinEstado++;continue;}
  if(COMPLETADOS.some(c=>estadoRaw.includes(c))){completadas++;continue;}

  activas++;
  if(!grupos[estadoRaw])grupos[estadoRaw]=[];
  grupos[estadoRaw].push({nombre,empresa,dias:diasTranscurridos});

  if(estadoRaw.includes('Requiere mi acción'))necesitanAccion.push('  • '+nombre+(empresa?' — '+empresa:''));
  if((estadoRaw.includes('Enviada')||estadoRaw.includes('Sin respuesta'))&&diasTranscurridos>=7){
    sinRespuesta30.push('  • '+nombre+(empresa?' — '+empresa:'')+' ('+diasTranscurridos+' días)');
  }
  if(diasTranscurridos>=30&&(estadoRaw.includes('Enviada')||estadoRaw.includes('Sin respuesta'))){
    sincerrar.push('  • '+nombre+(empresa?' — '+empresa:'')+' ('+diasTranscurridos+' días — VENCIDA)');
  }
}

let r='📊 *Reporte Semanal — '+today.toLocaleDateString('es-CL',{weekday:'long',day:'numeric',month:'long'})+'*\n\n';
r+='📌 *Activas: '+activas+'* | ✅ Completadas: '+completadas;
if(sinEstado)r+=' | _('+sinEstado+' sin categorizar)_';
r+='\n\n*Por estado:*\n';
for(const[e,lista]of Object.entries(grupos)){r+=e+': '+lista.length+'\n';}

if(necesitanAccion.length)r+='\n🚨 *Requieren tu acción:*\n'+necesitanAccion.join('\n')+'\n';
if(sinRespuesta30.length)r+='\n⏰ *Sin respuesta +7 días:*\n'+sinRespuesta30.join('\n')+'\n';
if(sincerrar.length)r+='\n🗄️ *Candidatas a cerrar (+30 días):*\n'+sincerrar.join('\n')+'\n_(Di "cerrar vencidas" al agente para confirmar)_\n';
if(!necesitanAccion.length&&!sinRespuesta30.length&&!sincerrar.length)r+='\n✨ Todo en orden, sin acciones pendientes.';

r+='\n\n🔗 [Ver en Notion](https://notion.so/2d03b76e193b808783c6fae54ef2fe08)';
return[{json:{report:r}}];

